WHERE NOTICE_NO = #{noticeNo}

mapper.select:
SELECT * FROM ( SELECT ROWNUM AS RN, A.* FROM ( SELECT R.REPORT_NO AS reportNo, R.TARGET_TYPE AS targetType, R.TARGET_NO AS targetNo, R.REASON AS reason, R.REPORT_STATUS AS reportStatus, TO_CHAR(R.REPORT_DATE, 'YYYY-MM-DD') AS reportDate, R.MEMBER_NO AS memberNo, M.NICKNAME AS reporterName, CASE WHEN R.TARGET_TYPE = 'travel' THEN T.TRAVEL_TITLE WHEN R.TARGET_TYPE = 'question' THEN Q.TITLE WHEN R.TARGET_TYPE = 'reply' THEN RP.CONTENT END AS targetTitle FROM REPORT R JOIN MEMBER M ON R.MEMBER_NO = M.MEMBER_NO LEFT JOIN TRAVEL_LIST T ON R.TARGET_TYPE = 'travel' AND R.TARGET_NO = T.TRAVEL_NO LEFT JOIN QLIST Q ON R.TARGET_TYPE = 'question' AND R.TARGET_NO = Q.Q_NO LEFT JOIN REPLY RP ON R.TARGET_TYPE = 'reply' AND R.TARGET_NO = RP.REPLY_NO WHERE 1=1
AND R.TARGET_TYPE = 'reply'
AND R.TARGET_TYPE IN ('travel', 'question')
AND R.REPORT_STATUS = #{status}
ORDER BY R.REPORT_DATE DESC ) A WHERE ROWNUM <= #{pi.currentPage} * #{pi.boardLimit} ) WHERE RN > (#{pi.currentPage} - 1) * #{pi.boardLimit}

